def run_command(command, description, cwd=None, env=None):
    """Run a shell command and handle errors."""
    logger.info(f"Starting: {description}")
    logger.info(f"Command: {' '.join(command) if isinstance(command, list) else command}")

    merged_env = os.environ.copy()
    if env:
        merged_env.update(env)

    try:
        result = subprocess.run(
            command,
            cwd=cwd or PROJECT_ROOT,
            env=merged_env,
            capture_output=True,
            text=True,
            timeout=300,
        )

        if result.stdout:
            logger.info(result.stdout.strip())
        if result.stderr:
            logger.warning(result.stderr.strip())

        if result.returncode != 0:
            logger.error(f"FAILED: {description} (exit code {result.returncode})")
            return False

        logger.info(f"SUCCESS: {description}")
        return True

    except subprocess.TimeoutExpired:
        logger.error(f"TIMEOUT: {description} exceeded 300s limit")
        return False
    except FileNotFoundError:
        logger.error(f"Command not found: {command[0] if isinstance(command, list) else command}")
        return False
    except Exception as e:
        logger.error(f"EXCEPTION during {description}: {e}")
        return False


def check_prerequisites():
    """Verify all prerequisites are met before deployment."""
    logger.info("=" * 60)
    logger.info("PHASE 0: Checking prerequisites")
    logger.info("=" * 60)

    errors = []

    # Check Python version
    python_version = sys.version_info
    logger.info(f"Python version: {python_version.major}.{python_version.minor}.{python_version.micro}")
    if python_version < (3, 7):
        errors.append(f"Python 3.7+ required, found {python_version.major}.{python_version.minor}")

    # Check requirements.txt exists
    if not os.path.isfile(REQUIREMENTS_FILE):
        errors.append(f"Requirements file not found: {REQUIREMENTS_FILE}")

    # Check pip is available
    if not run_command([sys.executable, "-m", "pip", "--version"], "Checking pip availability"):
        errors.append("pip is not available")

    # Check for test directory or test files
    has_tests = False
    if os.path.isdir(TEST_DIR):
        has_tests = True
    else:
        # Check for test files in project root
        for f in os.listdir(PROJECT_ROOT):
            if f.startswith("test_") and f.endswith(".py"):
                has_tests = True
                break

    if not has_tests:
        logger.warning("No test directory or test files found - tests will be skipped")

    if errors:
        for error in errors:
            logger.error(f"Prerequisite failed: {error}")
        return False

    logger.info("All prerequisites met")
    return True


def install_dependencies():
    """Install project dependencies from requirements.txt."""
    logger.info("=" * 60)
    logger.info("PHASE 1: Installing dependencies")
    logger.info("=" * 60)

    # Upgrade pip first
    run_command(
        [sys.executable, "-m", "pip", "install", "--upgrade", "pip"],
        "Upgrading pip",
    )

    # Install dependencies
    success = run_command(
        [
            sys.executable, "-m", "pip", "install",
            "-r", REQUIREMENTS_FILE,
            "--no-cache-dir",
            "--disable-pip-version-check",
        ],
        "Installing project dependencies",
    )

    if not success:
        return False

    # Install test dependencies if they exist
    test_requirements = os.path.join(PROJECT_ROOT, "requirements-test.txt")
    if os.path.isfile(test_requirements):
        success = run_command(
            [
                sys.executable, "-m", "pip", "install",
                "-r", test_requirements,
                "--no-cache-dir",
            ],
            "Installing test dependencies",
        )
        if not success:
            return False

    # Also ensure pytest is available for running tests
    run_command(
        [sys.executable, "-m", "pip", "install", "pytest", "pytest-cov"],
        "Ensuring pytest is available",
    )

    # Freeze installed packages for reproducibility
    run_command(
        [sys.executable, "-m", "pip", "freeze"],
        "Listing installed packages",
    )

    return True


