def run_tests():
    """Run the application test suite."""
    logger.info("=" * 60)
    logger.info("PHASE 2b: Running tests")
    logger.info("=" * 60)

    # Determine test target
    test_target = None
    if os.path.isdir(TEST_DIR):
        test_target = TEST_DIR
    else:
        # Look for test files in project root
        test_files = [f for f in os.listdir(PROJECT_ROOT) if f.startswith("test_") and f.endswith(".py")]
        if test_files:
            test_target = PROJECT_ROOT

    if test_target is None:
        logger.warning("No tests found - skipping test phase")
        return True

    # Run pytest with coverage
    success = run_command(
        [
            sys.executable, "-m", "pytest",
            test_target,
            "-v",
            "--tb=short",
            "--no-header",
            "-q",
            "--cov=.",
            "--cov-report=term-missing",
            "--cov-fail-under=0",  # Don't fail on coverage threshold by default
            "-x",  # Stop on first failure for fast feedback
        ],
        "Running test suite with pytest",
    )

    if not success:
        # Fallback: try running with unittest
        logger.info("pytest failed, trying unittest as fallback...")
        success = run_command(
            [sys.executable, "-m", "unittest", "discover", "-s", test_target, "-v"],
            "Running test suite with unittest",
        )

    return success


def compute_file_checksum(filepath):
    """Compute SHA256 checksum of a file."""
    sha256 = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


def clean_build_artifacts():
    """Clean previous build and dist directories."""
    logger.info("Cleaning previous build artifacts...")

    for directory in [DIST_DIR, BUILD_DIR]:
        if os.path.exists(directory):
            shutil.rmtree(directory)
            logger.info(f"Removed: {directory}")

    # Clean __pycache__ directories
    for root, dirs, files in os.walk(PROJECT_ROOT):
        for d in dirs:
            if d == "__pycache__":
                pycache_path = os.path.join(root, d)
                shutil.rmtree(pycache_path)
                logger.info(f"Removed: {pycache_path}")


